(window.webpackJsonp=window.webpackJsonp||[]).push([[579],{592:function(n){n.exports=JSON.parse('{"code":["<pre class=\\"hljs\\"><code><span class=\\"hljs-comment\\">/**\\n * Definition for a binary tree node.\\n * function TreeNode(val) {\\n *     this.val = val;\\n *     this.left = this.right = null;\\n * }\\n */</span>\\n<span class=\\"hljs-comment\\">/**\\n * <span class=\\"hljs-doctag\\">@param <span class=\\"hljs-type\\">{TreeNode}</span> <span class=\\"hljs-variable\\">root</span></span>\\n * <span class=\\"hljs-doctag\\">@return <span class=\\"hljs-type\\">{void}</span> </span>Do not return anything, modify root in-place instead.\\n */</span>\\n<span class=\\"hljs-keyword\\">var</span> flatten = <span class=\\"hljs-function\\"><span class=\\"hljs-keyword\\">function</span>(<span class=\\"hljs-params\\">root</span>) </span>{\\n  <span class=\\"hljs-keyword\\">if</span>(!root)<span class=\\"hljs-keyword\\">return</span> <span class=\\"hljs-literal\\">null</span>\\n  <span class=\\"hljs-keyword\\">let</span> l=root.left,\\n      r=root.right\\n  root.left=<span class=\\"hljs-literal\\">null</span>\\n  root.right=flatten(l)\\n  <span class=\\"hljs-keyword\\">let</span> node=root\\n  <span class=\\"hljs-keyword\\">while</span>(node.right)node=node.right\\n  node.right=flatten(r)\\n  <span class=\\"hljs-keyword\\">return</span> root\\n};\\n</code></pre>\\n"],"titleSlug":"flatten-binary-tree-to-linked-list","hasThinking":true,"thinking":"<hr>\\n<p>\u601d\u8def\uff1a</p>\\n<p>\u5bf9\u4e8e\u6bcf\u4e2a<code>root</code>\u8282\u70b9\uff0c\u5148\u5c06\u5b83\u7684\u5de6\u5b50\u6811\u548c\u53f3\u5b50\u6811\u5206\u522b\u4fdd\u5b58\u4e3a<code>l</code>\u548c<code>r</code>\uff1b</p>\\n<p>\u63a5\u7740\u7ee7\u7eed<code>flatten</code>\u5b83\u7684\u5de6\u5b50\u6811\uff0c\u5c06<code>flatten(l)</code>\u7684\u7ed3\u679c\u4f5c\u4e3a<code>root</code>\u7684\u65b0\u7684\u53f3\u5b50\u6811\uff0c\u56e0\u4e3a<code>flatten(l)</code>\u5df2\u7ecf\u662f\u4e00\u4e2a\u5e73\u94fa\u7684\u6811\uff0c\u56e0\u6b64\u53ef\u4ee5\u6cbf\u7740\u5b83\u7684\u53f3\u5b50\u6811\u4e00\u76f4\u627e\u5230\u6700\u540e\u4e00\u4e2a\u8282\u70b9<code>node</code>\uff0c\u7136\u540e\u5c06<code>root</code>\u539f\u6765\u7684\u53f3\u5b50\u6811<code>r</code>\uff0c\u4f5c\u4e3a<code>node</code>\u7684\u53f3\u5b50\u6811\u8fde\u63a5\u8d77\u6765\u3002</p>\\n","content":"<p>\u7ed9\u4f60\u4e8c\u53c9\u6811\u7684\u6839\u7ed3\u70b9 <code>root</code> \uff0c\u8bf7\u4f60\u5c06\u5b83\u5c55\u5f00\u4e3a\u4e00\u4e2a\u5355\u94fe\u8868\uff1a</p>\\n\\n<ul>\\n\\t<li>\u5c55\u5f00\u540e\u7684\u5355\u94fe\u8868\u5e94\u8be5\u540c\u6837\u4f7f\u7528 <code>TreeNode</code> \uff0c\u5176\u4e2d <code>right</code> \u5b50\u6307\u9488\u6307\u5411\u94fe\u8868\u4e2d\u4e0b\u4e00\u4e2a\u7ed3\u70b9\uff0c\u800c\u5de6\u5b50\u6307\u9488\u59cb\u7ec8\u4e3a <code>null</code> \u3002</li>\\n\\t<li>\u5c55\u5f00\u540e\u7684\u5355\u94fe\u8868\u5e94\u8be5\u4e0e\u4e8c\u53c9\u6811 <a href=\\"https://baike.baidu.com/item/%E5%85%88%E5%BA%8F%E9%81%8D%E5%8E%86/6442839?fr=aladdin\\" target=\\"_blank\\"><strong>\u5148\u5e8f\u904d\u5386</strong></a> \u987a\u5e8f\u76f8\u540c\u3002</li>\\n</ul>\\n\\n<p>\xa0</p>\\n\\n<p><strong>\u793a\u4f8b 1\uff1a</strong></p>\\n<img alt=\\"\\" src=\\"https://assets.leetcode.com/uploads/2021/01/14/flaten.jpg\\" style=\\"width: 500px; height: 226px;\\" />\\n<pre>\\n<strong>\u8f93\u5165\uff1a</strong>root = [1,2,5,3,4,null,6]\\n<strong>\u8f93\u51fa\uff1a</strong>[1,null,2,null,3,null,4,null,5,null,6]\\n</pre>\\n\\n<p><strong>\u793a\u4f8b 2\uff1a</strong></p>\\n\\n<pre>\\n<strong>\u8f93\u5165\uff1a</strong>root = []\\n<strong>\u8f93\u51fa\uff1a</strong>[]\\n</pre>\\n\\n<p><strong>\u793a\u4f8b 3\uff1a</strong></p>\\n\\n<pre>\\n<strong>\u8f93\u5165\uff1a</strong>root = [0]\\n<strong>\u8f93\u51fa\uff1a</strong>[0]\\n</pre>\\n\\n<p>\xa0</p>\\n\\n<p><strong>\u63d0\u793a\uff1a</strong></p>\\n\\n<ul>\\n\\t<li>\u6811\u4e2d\u7ed3\u70b9\u6570\u5728\u8303\u56f4 <code>[0, 2000]</code> \u5185</li>\\n\\t<li><code>-100 <= Node.val <= 100</code></li>\\n</ul>\\n\\n<p>\xa0</p>\\n\\n<p><strong>\u8fdb\u9636\uff1a</strong>\u4f60\u53ef\u4ee5\u4f7f\u7528\u539f\u5730\u7b97\u6cd5\uff08<code>O(1)</code> \u989d\u5916\u7a7a\u95f4\uff09\u5c55\u5f00\u8fd9\u68f5\u6811\u5417\uff1f</p>\\n","title":"114. \u4e8c\u53c9\u6811\u5c55\u5f00\u4e3a\u94fe\u8868","relatedTags":["\u6811","\u6df1\u5ea6\u4f18\u5148\u641c\u7d22"],"difficult":"Middle","lang":["javascript"],"uniqueID":"114"}')}}]);